var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"단장님. 방금 계측기가 뾰복! 하고 울렸어.","JPN":"団長。今計測器がピピッって鳴ったよ。","ENG":"Captain, the sensor just went beep-boop!","TWN":"團長，剛才測量儀器發出嘟嘟聲！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"파랑이들~. 오는 모양인데?","JPN":"青服～、来るみたい。","ENG":"Looks like the Blueys are on their way.","TWN":"藍移的人～要來了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그래. 무대에 설 배우들이 도착한 모양이군.","JPN":"ああ。舞台に立つ俳優たちが到着したようだ。","ENG":"Indeed. The actors have arrived for the grand stage.","TWN":"是啊，看起來演員們已經到達舞臺了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면 응당 그에 맞는 무대를 마련해야겠지.","JPN":"それなら当然、相応しい舞台を用意しないとな。","ENG":"Then we must prepare a stage worthy of their performance.","TWN":"那麼就應該為此準備一個合適的舞臺。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"으음~. 그런데 단장님. 다른 녀석들은 그렇다 쳐도 사자가 올까?","JPN":"うーん、でも団長。他のやつらはともかく、ライオンが来るかな？","ENG":"Hmm... But Captain, do you really think the Leo will show up?","TWN":"嗯~。不過團長，其他傢伙就算了，獅子會來嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"걔는 기사단 소속도 아니잖아?","JPN":"あいつは騎士団の所属でもないでしょ？","ENG":"She's not even part of the Order anymore.","TWN":"她不是騎士團成員嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"제 눈앞에서 소중한 것을 부수려 했으니 오지 않고서는 못 배기겠지.","JPN":"自分の目の前で大切なものを壊そうとしたのだ。来ないはずがない。","ENG":"I tried to destroy something precious in front of her. She won't be able to stay away.","TWN":"在我面前試圖破壞珍貴的東西，當然不會放過你。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"과거의 인연에 집착하는 것은 비단 그녀만이 아닐 테고 말이야.","JPN":"過去の絆に執着しているのは彼女だけではないだろう。","ENG":"Clinging to the past isn't something she alone suffers from.","TWN":"執著於過去的緣分，不僅僅是她一個人的事吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"아셀라 경. 명령을 하달하겠다.","JPN":"アセッラ卿。命令だ。","ENG":"Dame Ascella. I'm giving you your orders.","TWN":"亞瑟拉。下達命令吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"병력을 삼분으로 배치해, 전위에 강습조를 배치, 중위와 후위는 밀집대형을 유지.","JPN":"兵力を3つに分けて配置し、前衛に強襲組を配置、中衛と後衛には密集隊形を維持。","ENG":"Divide the forces into three. Deploy an assault squad at the front, and keep the middle and rear in tight formation.","TWN":"將兵力分為三部分，前方部署突擊隊員，中間和後方保持密集隊形。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그대는 중위에서 에스퀘데의 여식을 지키는데 전념해라.","JPN":"そなたは中衛でエスクェーデの娘を守ることに専念しろ。","ENG":"You are to stay in the center and guard the Esquede girl.","TWN":"你專注於保護埃斯庫德的女兒。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"응? 걔 하나 지키는데 굳이 지팡이를 써?","JPN":"えっ？　あの子1人を守るのに、杖を使うの？","ENG":"Huh? You're using the staff just to protect her?","TWN":"嗯？為了保護她，非得用復活之杖嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"연회를 돋울 곡조의 마련이다.","JPN":"宴会を盛り上げる曲調を準備するのだ。","ENG":"It's to compose the melody for tonight's feast.","TWN":"這是為宴會準備的樂曲。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"모처럼 얻은 재전의 무대에서 저들이 어중간한 태도로 임해서는 안 될 노릇이지.","JPN":"せっかく手に入れた再戦の舞台に、彼らが中途半端な態度で挑むことは許されない。","ENG":"We can't have them stepping onto the battlefield halfheartedly, not when we've prepared a stage like this.","TWN":"好不容易獲得了再戰的舞臺，我們可不能以半吊子的態度來應對。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 지팡이에 담겨 있던 클리파 허수 에너지도 거의 소실됐는데~?","JPN":"でも、杖に込められてたクリファ虚数エネルギーももうほぼなくなったよ～？","ENG":"But most of the Qlipha Imaginary Energy inside the Staff is already gone.","TWN":"但是杖中蘊含的逆卡巴拉虛數能量也幾乎消失了～？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"혹시라도 무리하면, 몸이 펑! 하고 터져버린다고!","JPN":"もし無理したら、体がドーン！　爆発しちゃうし！","ENG":"If I overuse it, I'll go boom and explode!","TWN":"如果勉強的話，身體會砰！地一聲爆炸喔！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면 죽어라.","JPN":"そうなったら、死ね。","ENG":"Then die.","TWN":"那麼去死吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"싸우다 죽는 것이 네 간악한 소원 중 하나가 아니었나?","JPN":"戦って死ぬことがそなたのよこしまな望みの一つだったのではないか？","ENG":"Wasn't dying in battle one of your twisted little wishes?","TWN":"戰鬥至死不是你邪惡的願望之一嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"어……","JPN":"えーっと……","ENG":"Uh...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"모르겠다. 단장님 말이니까 맞겠지, 뭐!","JPN":"わかんないや。団長の話だから、まあ合ってるよね！","ENG":"Whatever. If you say so, then sure!","TWN":"不知道。反正是團長說的，應該沒錯吧！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 저, 죽으러 갈게요~!","JPN":"じゃあアタシ、死にに行きます～！","ENG":"Then, I'm head out to die!","TWN":"那我就去送死囉～！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이걸로 전승을 실현시키기 위한 모든 준비는 마쳤다.","JPN":"これで伝承を実現させるためのすべての準備が整った。","ENG":"With this, all preparations to fulfill the legend are complete.","TWN":"至此，為實現傳承的一切準備都已完成。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"훼손된 레드시프트의 별의 무구에 담긴 별빛.","JPN":"レッドシフトの壊れた星の武具に込められた星の光。","ENG":"The starlight sealed in Red Shift's fractured Armament...","TWN":"破損的紅移星之武具中蘊含的星光。"},"stage":{"bg":"ALTERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그 출력을 감당하여, 일시적으로 무구의 역할을 대신할 리액터의 확보.","JPN":"その出力に耐え、一時的に武具の役割を担当するリアクターの確保。","ENG":"We've secured the reactor that will momentarily take the Armament's place by enduring that output.","TWN":"為了承受那種輸出，暫時獲取能夠替代武具作用的電抗器。"},"stage":{"bg":"ALTERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"클리포트 게임 당시 처녀자리의 별빛을 흡수했던 마창 레나투스.","JPN":"クリフォトゲーム当時、乙女座の星の光を吸収した魔槍レナトゥス。","ENG":"The Evil Spear Renatus, which absorbed Virgo's starlight during the Qliphoth Game...","TWN":"逆卡巴拉遊戲時吸收了處女座星光的魔槍雷納圖斯。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};